from elasticsearch import Elasticsearch, RequestsHttpConnection
from flask import Flask, request, jsonify
import re

app = Flask(__name__)

# Initialize Elasticsearch client
es = Elasticsearch(
    hosts=[{'host': 'localhost', 'port': 9200}],
    connection_class=RequestsHttpConnection,
    http_auth=('user', 'password'),  # Use secure methods to handle credentials
    use_ssl=True,
    verify_certs=True
)

# Allowlist of safe script patterns
SAFE_SCRIPT_PATTERNS = [
    r"^doc\['\w+'\]\.value\s*[\+\-\*/]\s*\d+$",  # Simple arithmetic operations
    r"^Math\.\w+\(doc\['\w+'\]\.value\)$"         # Math functions
]

def is_safe_script(script):
    return any(re.match(pattern, script) for pattern in SAFE_SCRIPT_PATTERNS)

@app.route('/aggregate', methods=['POST'])
def aggregate():
    try:
        script = request.json.get('script', '')
        
        # Validate the script against allowlist patterns
        if not is_safe_script(script):
            return jsonify({'error': 'Invalid script'}), 400
        
        # Define the aggregation query with the validated script
        aggregation_query = {
            "size": 0,
            "aggs": {
                "dynamic_script": {
                    "scripted_metric": {
                        "init_script": "state.transactions = []",
                        "map_script": script,
                        "combine_script": "double sum = 0; for (t in state.transactions) { sum += t } return sum",
                        "reduce_script": "double sum = 0; for (a in states) { sum += a } return sum"
                    }
                }
            }
        }
        
        # Execute the aggregation query
        response = es.search(index='your_index', body=aggregation_query)
        return jsonify(response['aggregations']['dynamic_script'])
    
    except Exception as e:
        return jsonify({'error': str(e)}), 500

